import React from 'react';
import './Services.css';
import Footer from './Footer';
impo
const teamMembers = [
  {
    id: 1,
    name: 'Williamson',
    role: 'Web Developer',
    image: P1, // Use P1 for all images
    social: {
      facebook: '#',
      twitter: '#',
      google: '#',
    },
  },
  {
    id: 2,
    name: 'Kristiana',
    role: 'Web Designer',
    image: P1,
    social: {
      facebook: '#',
      twitter: '#',
      google: '#',
    },
  },
  {
    id: 3,
    name: 'John Doe',
    role: 'UI/UX Designer',
    image: P1,
    social: {
      facebook: '#',
      twitter: '#',
      google: '#',
    },
  },
  {
    id: 4,
    name: 'Jane Smith',
    role: 'Frontend Developer',
    image: P1,
    social: {
      facebook: '#',
      twitter: '#',
      google: '#',
    },
  },
  {
    id: 5,
    name: 'Alice Johnson',
    role: 'Backend Developer',
    image: P1,
    social: {
      facebook: '#',
      twitter: '#',
      google: '#',
    },
  },
  {
    id: 6,
    name: 'Bob Brown',
    role: 'Full Stack Developer',
    image: P1,
    social: {
      facebook: '#',
      twitter: '#',
      google: '#',
    },
  },
];

const Services = () => {
  return (
    <div className='services'>
      <div className="our-team-heading">
        <h1>OUR TEAM</h1>
      </div>
      <div className="container">
        <div className="row">
          {teamMembers.map((member) => (
            <div className="col-md-4 col-sm-6" key={member.id}>
              <div className="our-team">
                <img src={member.image} alt={member.name} />
                <div className="team-content">
                  <h3 className="title">{member.name}</h3>
                  <span className="post">{member.role}</span>
                  <ul className="social">
                    <li>
                      <a href={member.social.facebook}>
                        <i className="fab fa-facebook-f"></i>
                      </a>
                    </li>
                    <li>
                      <a href={member.social.twitter}>
                        <i className="fab fa-twitter"></i>
                      </a>
                    </li>
                    <li>
                      <a href={member.social.google}>
                        <i className="fab fa-google-plus-g"></i>
                      </a>
                    </li>
                  </ul>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
      <Footer />
    </div>
  );
};

export default Services;
